const result = await apiClient.post('/api/v1/data', payload, {
  retry: {
    maxAttempts: 5,
    delay: 2000,
    backoffMultiplier: 2,
  },
});
```

### 7.4 批量请求

```typescript
const results = await apiClient.batch([
  { method: 'GET', url: '/api/v1/users' },
