const user = await apiClient.getData<User>('/api/v1/users/123');
```

### 7.2 带缓存的请求

```typescript
const result = await apiClient.get<User[]>('/api/v1/users', {
  cache: true,  // 启用缓存
});
```

### 7.3 带重试的请求

```typescript
// 使用默认重试配置
const result = await apiClient.post('/api/v1/data', payload, {
  retry: true,
});

// 自定义重试配置
const result = await apiClient.post('/api/v1/data', payload, {
  retry: {
    maxAttempts: 5,
    delay: 2000,
    backoffMultiplier: 2,
  },
});
```

### 7.4 批量请求

```typescript
const results = await apiClient.batch([
  { method: 'GET', url: '/api/v1/users' },
  { method: 'GET', url: '/api/v1/assets' },
  { method: 'POST', url: '/api/v1/logs', data: { action: 'view' } },
]);
