import { AxiosResponse, InternalAxiosRequestConfig } from 'axios';

// ==================== 基础响应类型 ====================

/**
 * 标准API响应格式
 * 适用于大部分后端API接口
 */
export interface StandardApiResponse<T = unknown> {
  success: boolean;
  data: T;
  message?: string;
  code?: string;
  timestamp?: string;
}

/**
 * 分页响应格式
 * 适用于列表类API接口
 */
export interface PaginatedApiResponse<T = unknown> {
  success: boolean;
  data: {
    items: T[];
    pagination: {
      page: number;
      pageSize: number;
      total: number;
      totalPages: number;
    };
  };
  message?: string;
}

/**
 * 简化响应格式
 * 直接返回数据，无包装结构
 */
export interface DirectResponse<T = unknown> {
  [key: string]: T;
}

/**
 * 错误响应格式
 */
export interface ErrorResponse {
  success: false;
  error: {
    code: string;
    message: string;
    details?: Record<string, unknown>;
    timestamp?: string;
  };
}

// ==================== 业务响应类型 ====================

