 * 响应数据提取结果
 */
export interface ExtractResult<T> {
  success: boolean;
  data?: T;
  error?: string;
  rawResponse: AxiosResponse;
}

/**
 * 响应检测配置
 */
export interface ResponseDetectionConfig {
  // 成功检测字段
  successField?: string;
  // 数据字段
  dataField?: string;
  // 错误检测
  errorFields?: string[];
  // 是否启用严格模式
  strict?: boolean;
}

/**
