    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`获取缺陷报告失败: ${response.statusText}`);
    }
    const data = (await response.json()) as { defects: DefectReport[]; total: number };
    return {
      success: true,
      data,
    };
  }

