   * 触发测试覆盖率扫描
   */
  async triggerCoverageScan(options?: {
    backend?: boolean;
    frontend?: boolean;
    specific_modules?: string[];
    parallel?: boolean;
  }): Promise<
    ApiResponse<{
      scan_id: string;
      status: 'started' | 'queued';
